      "assessmentFeedback": "<p><span style=\"font-weight: normal;\">Use recap questions to check prior understanding.</span></p><p><span style=\"font-weight: normal;\">Use questioning during explanation.</span></p><p><span style=\"font-weight: normal;\">Check student notes and activity responses while circulating.</span></p>",
