      "generalCapabilities": "<span style=\"font-weight: normal;\"><span data-start=\"1399\" data-end=\"1411\">Literacy</span> — using trade terms such as imports, exports, trade partners, economies of scale and global economy.<br data-start=\"1512\" data-end=\"1515\">\n<span data-start=\"1515\" data-end=\"1527\">Numeracy</span> — interpreting trade tables and creating a chart using Excel/Google Sheets.<br data-start=\"1603\" data-end=\"1606\">\n<span data-start=\"1606\" data-end=\"1624\">ICT Capability</span> — using devices to research DFAT data and create a presentation.<br data-start=\"1689\" data-end=\"1692\">\n<span data-start=\"1692\" data-end=\"1726\">Critical and Creative Thinking</span> — analysing trade patterns and explaining Australia’s economic links with other countries.<br data-start=\"1817\" data-end=\"1820\">\n<span data-start=\"1820\" data-end=\"1854\">Personal and Social Capability</span> — working in groups to research, prepare and present.</span>",
      "learningIntentions": "<span style=\"font-weight: normal;\">Students will understand how Australia engages with Asia and the broader global economy through trade.</span>",
      "successCriteria": "<p data-start=\"2058\" data-end=\"2122\"><span style=\"font-weight: normal;\">Students can explain the difference between imports and exports.</span></p>\n<p data-start=\"2124\" data-end=\"2190\"><span style=\"font-weight: normal;\">Students can identify key features of Australia’s trade with Asia.</span></p>\n<p data-start=\"2192\" data-end=\"2249\"><span style=\"font-weight: normal;\">Students can explain why trade is important to Australia.</span></p>\n<p data-start=\"2251\" data-end=\"2319\"><span style=\"font-weight: normal;\">Students can use data to describe Australia’s trading relationships.</span></p>\n<p data-start=\"2321\" data-end=\"2416\"><span style=\"font-weight: normal;\">Students can research one country’s trade relationship with Australia and present key findings.</span></p>",
